    "html": "<div class=\"radio-input\">\n  <label class=\"label\">\n    <input type=\"radio\" name=\"radio\" checked=\"\">\n    <span class=\"check\"></span>\n  </label>\n  <label class=\"label\">\n    <input type=\"radio\" name=\"radio\">\n    <span class=\"check\"></span>\n  </label>\n      \n  <label class=\"label\">\n    <input type=\"radio\" name=\"radio\">\n    <span class=\"check\"></span>\n  </label>\n</div>",
    "css": "/* From Uiverse.io by AmIt-DasIT - Tags: dark, shadow, radio, neumorphism */\n.radio-input .label input {\n  display: none;\n}\n\n.radio-input {\n  display: flex;\n  gap: 20px;\n}\n\n.radio-input .label {\n  display: flex;\n}\n\n.radio-input .label .check {\n  width: 30px;\n  height: 30px;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  border-radius: 50%;\n  cursor: pointer;\n  transition: 0.3s;\n  border: 3px solid transparent;\n  box-shadow: 3px 3px 6px rgba(0, 0, 0, 0.5),\n   -1px -1px 4px rgba(255, 255, 255, 0.5);\n}\n\n.radio-input .label input:checked + .check {\n  box-shadow: 3px 3px 6px rgba(0, 0, 0, 0.5),\n   -1px -1px 4px rgba(255, 255, 255, 0.5),\n   inset 3px 3px 6px rgba(0, 0, 0, 0.5),\n   inset -1px -1px 4px rgba(255, 255, 255, 0.5);\n  transform: scale(1.1);\n}"
