    "animationLevel": "high",
    "html": "<div class=\"mydict\">\n\t<div>\n\t\t<label>\n\t\t\t<input type=\"radio\" name=\"radio\" checked=\"\">\n\t\t\t<span>Women</span>\n\t\t</label>\n\t\t<label>\n\t\t\t<input type=\"radio\" name=\"radio\">\n\t\t\t<span>Men</span>\n\t\t</label>\n\t\t<label>\n\t\t\t<input type=\"radio\" name=\"radio\">\n\t\t\t<span>Divided</span>\n\t\t</label>\n\t\t\n\t</div>\n</div>",
    "css": "/* From Uiverse.io by Pradeepsaranbishnoi - Tags: radio */\n:focus {\n  outline: 0;\n  border-color: #2260ff;\n  box-shadow: 0 0 0 4px #b5c9fc;\n}\n\n.mydict div {\n  display: flex;\n  flex-wrap: wrap;\n  margin-top: 0.5rem;\n  justify-content: center;\n}\n\n.mydict input[type=\"radio\"] {\n  clip: rect(0 0 0 0);\n  clip-path: inset(100%);\n  height: 1px;\n  overflow: hidden;\n  position: absolute;\n  white-space: nowrap;\n  width: 1px;\n}\n\n.mydict input[type=\"radio\"]:checked + span {\n  box-shadow: 0 0 0 0.0625em #0043ed;\n  background-color: #dee7ff;\n  z-index: 1;\n  color: #0043ed;\n}\n\nlabel span {\n  display: block;\n  cursor: pointer;\n  background-color: #fff;\n  padding: 0.375em .75em;\n  position: relative;\n  margin-left: .0625em;\n  box-shadow: 0 0 0 0.0625em #b5bfd9;\n  letter-spacing: .05em;\n  color: #3e4963;\n  text-align: center;\n  transition: background-color .5s ease;\n}\n\nlabel:first-child span {\n  border-radius: .375em 0 0 .375em;\n}\n\nlabel:last-child span {\n  border-radius: 0 .375em .375em 0;\n}"
