    "animationLevel": "high",
    "html": "<div class=\"radio-input\">\n  <div class=\"container\">\n    <label>\n      <input value=\"value-1\" name=\"value-radio\" checked=\"\" id=\"value-1\" type=\"radio\">\n      <div class=\"loader\"></div>\n    </label>\n    <label>\n      <input value=\"value-2\" name=\"value-radio\" id=\"value-2\" type=\"radio\">\n      <div class=\"loader\"></div>\n    </label>\n    <label>\n      <input value=\"value-3\" name=\"value-radio\" id=\"value-3\" type=\"radio\">\n      <div class=\"loader\"></div>\n    </label>\n </div>\n</div>",
    "css": "/* From Uiverse.io by Tsiangana - Tags: futuristic, animated, futuristic-radio-buttons */\n.radio-input label {\n  position: relative;\n  display: flex;\n  border-radius: 99999px;\n  margin: 8px;\n  width: 3em;\n  height: 3em;\n  margin-top: -35px;\n}\n\n.radio-input input {\n  position: absolute;\n  border-radius: 50%;\n  appearance: unset;\n  inset: 0.95em;\n  margin: 0;\n  cursor: pointer;\n  background-color: rgb(74, 156, 233);\n  filter: drop-shadow(0 0 10px rgb(74, 156, 233));\n}\n\n.radio-input input:checked {\n  transition: .9s linear;\n  background-color: #fff;\n  z-index: 500;\n}\n\n.radio-input .container {\n  width: 100%;\n  height: 100%;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n}\n\n.radio-input .container .loader {\n  height: 25px;\n  width: 25px;\n  border-radius: 50%;\n  border: 1px solid;\n  position: absolute;\n  bottom: -25px;\n  left: 10.5px;\n  transform-origin: 50% 60%;\n  transform: perspective(200px) rotateX(66deg);\n  z-index: -1;\n  background: linear-gradient(315deg, #cacaca, #f0f0f0);\n  box-shadow: -6px -6px 11px #c1c1c1,\n             6px 6px 11px #ffffff;\n}\n\n#value-1[type='radio']:checked:after {\n  content: '';\n  position: absolute;\n  width: 10px;\n  height: 10px;\n  background: #fff;\n  border-radius: 50%;\n  top: 23px;\n  animation: 2.2s  lua infinite ease-in-out;\n  animation-timing-function: linear;\n}\n\n#value-2[type='radio']:checked:after {\n  content: '';\n  position: absolute;\n  width: 10px;\n  height: 10px;\n  background: rgba(19, 219, 226, 0.719);\n  border-radius: 50%;\n  top: 23px;\n  animation: 2.2s  lua infinite ease-in-out;\n  animation-timing-function: linear;\n}\n\n#value-3[type='radio']:checked:after {\n  content: '';\n  position: absolute;\n  width: 10px;\n  height: 10px;\n  background: rgba(29, 29, 23, 0.979);\n  border-radius: 50%;\n  top: 23px;\n  animation: 2.2s lua  infinite ease-in-out;\n  animation-timing-function: linear;\n}\n\n@keyframes lua {\n  0% {\n    z-index: 5;\n  }\n\n  50% {\n    transform: translateX(1.5em) translateY(-2.5em);\n  }\n\n  100% {\n    z-index: -5;\n    background: none;\n  }\n}"
