    "css": "/* From Uiverse.io by Yaya12085 - Tags: button, hover, radio, futuristic */\n.radio-input {\n  display: flex;\n  justify-content: space-between;\n  align-items: center;\n}\n\n.radio-input input {\n  display: none;\n}\n\n.radio-input input + label {\n  position: relative;\n  height: 40px;\n  width: 40px;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  font-size: 20px;\n  line-height: 1;\n  font-weight: 600;\n  text-shadow: 0 1px #bbb,\n                0 2px #bbb,\n                0 3px #bbb;\n  color: #fff;\n  text-align: center;\n  text-transform: uppercase;\n  cursor: pointer;\n  background-color: #444;\n  border-radius: 30px;\n  box-shadow: 0 5px 15px rgba(0, 0, 0, 0.3);\n  padding: 4px;\n  transition: background-color 0.3s ease, transform 0.3s ease;\n}\n\n.radio-input label:hover {\n  background-color: #FBB03B;\n}\n\n.radio-input input + label::before {\n  content: \"\";\n  position: absolute;\n  top: -5px;\n  left: -5px;\n  right: -5px;\n  bottom: -5px;\n  background-color: transparent;\n  border: 2px solid #fff;\n  border-bottom: 2px dashed #fff;\n  border-radius: 30px;\n  transition: border-color 0.3s ease;\n}\n\n.radio-input input:checked + label {\n  background-color: #D4145A;\n  background-image: linear-gradient(to top left, #D4145A, #FBB03B);\n  color: #000;\n  transform: scale(1.2);\n  z-index: 1;\n}\n\n.radio-input input:checked + label::before {\n  border-color: #D4145A;\n  transform: rotate(90deg);\n  transition: transform .15s ease;\n  animation: pulse-border 1s ease infinite alternate-reverse;\n}\n\n@keyframes pulse-border {\n  0% {\n    border-color: #D4145A;\n  }\n\n  50% {\n    border-color: #D4145A;\n  }\n\n  100% {\n    transform: scale(1.08);\n    border-color: #D4145A;\n  }\n}"
