    "css": "/* From Uiverse.io by aadium - Tags: cyberpunk, radio, futuristic */\n.container input[type=\"radio\"] {\n  position: absolute;\n  opacity: 0;\n  cursor: pointer;\n  height: 0;\n  width: 0;\n}\n\n.container {\n  display: inline-block;\n  position: relative;\n  cursor: pointer;\n  font-size: 17px;\n  width: 5em;\n  height: 2.5em;\n  user-select: none;\n  border: none;\n}\n\n.selected {\n  position: absolute;\n  top: 0;\n  left: 0;\n  width: 100%;\n  height: 100%;\n}\n\n#leftradio {\n  border-bottom-left-radius: 2.5em;\n  border-top-left-radius: 2.5em;\n  border-bottom-right-radius: 0;\n  border-top-right-radius: 0;\n  border: 3px solid #78cce2;\n  background-color: transparent;\n  transition: 0.2s ease-in;\n}\n\n#rightradio {\n  border-bottom-right-radius: 2.5em;\n  border-top-right-radius: 2.5em;\n  border-bottom-left-radius: 0;\n  border-top-left-radius: 0;\n  border: 3px solid #defe47;\n  background-color: transparent;\n  transition: 0.2s linear;\n}\n\n#middleradio {\n  border: 3px solid #f887ff;\n  background-color: transparent;\n  transition: 0.2s linear;\n}\n\n.selected:after {\n  content: '';\n  position: absolute;\n  background-color: 78cce2;\n  width: 100%;\n  height: 90%;\n  transform: scale(0);\n  transition: 0.2s ease-out;\n}\n\n#leftradio:hover {\n  border-bottom-left-radius: 2.5em;\n  border-top-left-radius: 2.5em;\n  border-bottom-right-radius: 0;\n  border-top-right-radius: 0;\n  border: 3px solid #78cce2;\n  background-color: #78cce2;\n}\n\n#leftradio::after {\n  top: 0%;\n  height: 100%;\n  border-bottom-left-radius: 2.5em;\n  border-top-left-radius: 2.5em;\n  border-bottom-right-radius: 0;\n  border-top-right-radius: 0;\n  border: none;\n  background-color: #78cce2;\n  box-shadow: 0em 0em 4em 0.1em #78cce2;\n}\n\n#rightradio:hover {\n  border-bottom-right-radius: 2.5em;\n  border-top-right-radius: 2.5em;\n  border-bottom-left-radius: 0;\n  border-top-left-radius: 0;\n  border: 3px solid #defe47;\n  background-color: #defe47;\n}\n\n#rightradio::after {\n  left: -3%;\n  top: -1%;\n  border-bottom-right-radius: 2.5em;\n  border-top-right-radius: 2.5em;\n  border-bottom-left-radius: 0;\n  border-top-left-radius: 0;\n  border: 3px solid #defe47;\n  background-color: #defe47;\n  box-shadow: 0em 0em 4em 0.1em #defe47;\n}\n\n#middleradio:hover {\n  border: 3px solid #f887ff;\n  background-color: #f887ff;\n}\n\n#middleradio::after {\n  left: -3%;\n  top: -3%;\n  border: 3px solid #f887ff;\n  background-color: #f887ff;\n  box-shadow: 0em 0em 4em 0.1em #f887ff;\n}\n\n.container input[type=\"radio\"]:checked ~ .selected:after {\n  transform: scale(1);\n}"
