    "html": "<div class=\"radio-group\">\n  <label class=\"radio-button\">\n    <input type=\"radio\" name=\"radio\" value=\"option1\">\n    <svg class=\"radio-icon\" viewBox=\"0 0 24 24\">\n      <circle cx=\"12\" cy=\"12\" r=\"8\"></circle>\n      <circle cx=\"12\" cy=\"12\" r=\"5\"></circle>\n    </svg>\n    <div class=\"radio-text\">Option 1</div>\n  </label>\n  <label class=\"radio-button\">\n    <input type=\"radio\" name=\"radio\" value=\"option2\">\n    <svg class=\"radio-icon\" viewBox=\"0 0 24 24\">\n      <circle cx=\"12\" cy=\"12\" r=\"8\"></circle>\n      <circle cx=\"12\" cy=\"12\" r=\"5\"></circle>\n    </svg>\n    <div class=\"radio-text\">Option 2</div>\n  </label>\n  <label class=\"radio-button\">\n    <input type=\"radio\" name=\"radio\" value=\"option3\">\n    <svg class=\"radio-icon\" viewBox=\"0 0 24 24\">\n      <circle cx=\"12\" cy=\"12\" r=\"8\"></circle>\n      <circle cx=\"12\" cy=\"12\" r=\"5\"></circle>\n    </svg>\n    <div class=\"radio-text\">Option 3</div>\n  </label>\n</div>",
    "css": "/* From Uiverse.io by ahmed150up - Tags: radio */\n.radio-group {\n  display: flex;\n  flex-direction: column;\n}\n\n.radio-button {\n  display: flex;\n  align-items: center;\n  margin-bottom: 15px;\n  cursor: pointer;\n}\n\n.radio-icon {\n  width: 20px;\n  height: 20px;\n  margin-right: 10px;\n  fill: #fff;\n  transition: all 0.3s ease-in-out;\n}\n\n.radio-button:hover .radio-icon {\n  transform: scale(1.2);\n  fill: #2ed573;\n}\n\n.radio-button input[type=\"radio\"] {\n  opacity: 0;\n  position: absolute;\n}\n\n.radio-text {\n  font-size: 18px;\n  color: #fff;\n  font-weight: bold;\n}\n\n.radio-button::before {\n  content: \"\";\n  display: inline-block;\n  width: 20px;\n  height: 20px;\n  border-radius: 50%;\n  border: 2px solid #fff;\n  margin-right: 10px;\n  transition: all 0.3s ease-in-out;\n}\n\n.radio-button:hover .radio-text {\n  font-size: 18px;\n  color: #2ed573;\n  font-weight: bold;\n}\n\n.radio-button:hover::before {\n  border: 2px solid #2ed573;\n}\n\n.radio-button input[type=\"radio\"]:checked + .radio-icon {\n  fill: #2ed573;\n}\n\n.radio-button input[type=\"radio\"]:checked + .radio-icon circle:last-child {\n  opacity: 1;\n}"
