    "css": "/* From Uiverse.io by asgardOP  - Tags: button, smooth, radio, menu, hover effect, css effect, buttons */\n#navbody {\n  width: 300px;\n  height: 60px;\n  background-color: rgb(255, 255, 255);\n  border-radius: 40px;\n  box-shadow: 0px 10px 15px rgba(0, 0, 0, 0.041);\n  align-items: center;\n  justify-content: center;\n  display: flex;\n}\n\n.ul {\n  list-style: none;\n  width: 100%;\n  background-color: transparent;\n  display: flex;\n  justify-content: space-between;\n  margin-top: 5px;\n}\n\n.ul .li {\n  display: inline-block;\n}\n\n.radio {\n  display: none;\n}\n\n.svg {\n  width: 70px;\n  height: 70px;\n  opacity: 80%;\n  cursor: pointer;\n  padding: 13px 20px;\n  transition: 0.2s;\n}\n\n.ul .li .svg:hover {\n  transition: 0.1s;\n  color: rgb(235, 40, 176);\n  position: relative;\n  margin-top: -4px;\n  opacity: 100%;\n}\n\n.radio:checked + label .li .svg {\n  color: rgb(235, 40, 176);\n  fill-rule: evenodd;\n}"
